uint32_t Assets::CalculateChecksum(const char* data, uint32_t length) {
    const uint8_t* bytes = reinterpret_cast<const uint8_t*>(data);
    uint32_t sum = 0;
    for (uint32_t i = 0; i < length; ++i) {
        sum += bytes[i];
    }
    return static_cast<uint16_t>(sum);
}
