bool Assets::InitializePartition()
{
    // Find and validate partition
    const esp_partition_t* partition = esp_partition_find_first(
        ESP_PARTITION_TYPE_DATA, ESP_PARTITION_SUBTYPE_DATA_SPIFFS, "assets");

    if (partition == nullptr)
    {
        ESP_LOGE(TAG, "Failed to find assets partition");
        return false;
    }

    // Map partition into memory
    esp_err_t err = esp_partition_mmap(partition, 0, partition->size, 
                                       ESP_PARTITION_MMAP_DATA, 
                                       (const void**)&mmap_root_, &mmap_handle_);

    if (err != ESP_OK)
    {
        ESP_LOGE(TAG, "Failed to map assets partition: %s", esp_err_to_name(err));
        return false;
    }

    // Validate partition header and magic number
    const mmap_header* header = reinterpret_cast<const mmap_header*>(mmap_root_);
    if (header->magic != ASSETS_MAGIC_NUMBER)
    {
        ESP_LOGE(TAG, "Invalid assets partition magic number");
        return false;
    }

    // Validate checksum of header
    uint32_t header_checksum = CalculateChecksum(reinterpret_cast<const char*>(header), 
                                                 sizeof(mmap_header) - sizeof(uint32_t));
    if (header_checksum != header->checksum)
    {
        ESP_LOGE(TAG, "Header checksum mismatch");
        return false;
    }

    // Parse asset table from mapped memory
    uint32_t stored_files = header->file_count;
    const mmap_assets_table* table = reinterpret_cast<const mmap_assets_table*>(
        mmap_root_ + sizeof(mmap_header));

    // Build asset index map
    assets_.clear();
    checksum_valid_ = true;

    for (size_t i = 0; i < stored_files; i++)
    {
        const mmap_assets_table* item = &table[i];

        // Validate asset name
        if (item->asset_name[0] == '\0')
        {
            ESP_LOGW(TAG, "Skipping empty asset name at index %d", i);
            continue;
        }

        // Validate asset offset and size
        if (item->asset_offset < 0 || item->asset_size <= 0)
        {
            ESP_LOGW(TAG, "Invalid asset dimensions for %s", item->asset_name);
            continue;
        }

        // Calculate actual asset offset (accounting for header and table)
        size_t actual_offset = static_cast<size_t>(sizeof(mmap_header) + 
                                                  sizeof(mmap_assets_table) * stored_files + 
                                                  item->asset_offset);

        // Validate asset location within partition bounds
        if (actual_offset + item->asset_size > partition->size)
        {
            ESP_LOGW(TAG, "Asset %s extends beyond partition bounds", item->asset_name);
            continue;
        }

        Asset asset = {
            .size = static_cast<size_t>(item->asset_size),
            .offset = actual_offset
        };

        assets_[std::string(item->asset_name)] = asset;
    }

    ESP_LOGI(TAG, "Successfully initialized assets partition with %zu files", assets_.size());
    return true;
}

