bool Assets::Download(std::string url, std::function<void(int progress, size_t speed)> progress_callback)
{
    // Open HTTP connection
    auto network = Board::GetInstance().GetNetwork();
    auto http = network->CreateHttp(0);
    if (!http->Open("GET", url))
    {
        ESP_LOGE(TAG, "Failed to open HTTP connection");
        return false;
    }

    // Check status code
    if (http->GetStatusCode() != 200)
    {
        ESP_LOGE(TAG, "Failed to get assets, status code: %d", http->GetStatusCode());
        return false;
    }

    size_t content_length = http->GetBodyLength();
    if (content_length == 0)
    {
        ESP_LOGE(TAG, "Failed to get content length");
        return false;
    }

    // Get partition for writing
    const esp_partition_t* partition_ = esp_partition_find_first(
        ESP_PARTITION_TYPE_DATA, ESP_PARTITION_SUBTYPE_DATA_NVS, "assets");
    if (partition_ == NULL)
    {
        ESP_LOGE(TAG, "Failed to find assets partition");
        return false;
    }

    // Erase flash partition
    const size_t SECTOR_SIZE = esp_partition_get_main_flash_sector_size();
    size_t sectors_to_erase = (content_length + SECTOR_SIZE - 1) / SECTOR_SIZE;
    size_t total_erase_size = sectors_to_erase * SECTOR_SIZE;

    size_t current_sector = 0;
    while (current_sector < sectors_to_erase)
    {
        size_t sector_start = current_sector * SECTOR_SIZE;
        esp_err_t err = esp_partition_erase_range(partition_, sector_start, SECTOR_SIZE);
        if (err != ESP_OK)
        {
            ESP_LOGE(TAG, "Failed to erase sector %u at offset %u: %s", 
                     current_sector, sector_start, esp_err_to_name(err));
            return false;
        }
        current_sector++;
    }

    // Prepare buffer for downloading
    const size_t BUFFER_SIZE = 1024;
    uint8_t* buffer = new uint8_t[BUFFER_SIZE];
    if (buffer == nullptr)
    {
        ESP_LOGE(TAG, "Failed to allocate buffer");
        return false;
    }

    // Download and write data
    size_t total_written = 0;
    auto last_calc_time = esp_timer_get_time();
    size_t recent_written = 0;
    size_t start_time = esp_timer_get_time();

    while (total_written < content_length)
    {
        size_t to_read = std::min(BUFFER_SIZE, content_length - total_written);
        int ret = http->ReadBody(buffer, to_read);
        if (ret <= 0)
        {
            ESP_LOGE(TAG, "Failed to read from HTTP connection");
            delete[] buffer;
            return false;
        }

        // Write to flash
        esp_err_t err = esp_partition_write(partition_, total_written, buffer, ret);
        if (err != ESP_OK)
        {
            ESP_LOGE(TAG, "Failed to write to assets partition at offset %u: %s", 
                     total_written, esp_err_to_name(err));
            delete[] buffer;
            return false;
        }

        total_written += ret;
        recent_written += ret;

        // Update progress periodically
        if (esp_timer_get_time() - last_calc_time >= 1000000 || total_written == content_length || ret == 0)
        {
            size_t progress = total_written * 100 / content_length;

            // Calculate speed (bytes per second)
            size_t elapsed_time = esp_timer_get_time() - start_time;
            size_t speed = 0;
            if (elapsed_time > 0)
            {
                speed = (total_written * 1000000) / elapsed_time; // bytes per second
            }

            if (progress_callback)
            {
                progress_callback(progress, speed);
            }

            last_calc_time = esp_timer_get_time();
            recent_written = 0;
        }
    }

    delete[] buffer;

    // Initialize partition after successful download
    if (!InitializePartition())
    {
        ESP_LOGE(TAG, "Failed to initialize partition after download");
        return false;
    }

    return true;
}

