bool IsValidTransition(DeviceState fromState, DeviceState toState) const {
    // Define valid state transitions for a typical embedded device
    // This is a common pattern for state machine validation

    switch (fromState) {
        case DEVICE_STATE_OFF:
            // Can only transition to ON state
            return (toState == DEVICE_STATE_ON);

        case DEVICE_STATE_ON:
            // Can transition to various states including OFF, ERROR, etc.
            return (toState == DEVICE_STATE_OFF || 
                   toState == DEVICE_STATE_RUNNING || 
                   toState == DEVICE_STATE_ERROR);

        case DEVICE_STATE_RUNNING:
            // Can transition to OFF, ERROR, or PAUSED
            return (toState == DEVICE_STATE_OFF || 
                   toState == DEVICE_STATE_ERROR || 
                   toState == DEVICE_STATE_PAUSED);

        case DEVICE_STATE_PAUSED:
            // Can resume running or go to off/error
            return (toState == DEVICE_STATE_RUNNING || 
                   toState == DEVICE_STATE_OFF || 
                   toState == DEVICE_STATE_ERROR);

        case DEVICE_STATE_ERROR:
            // Only valid transition is to OFF or RUNNING (if recovery possible)
            return (toState == DEVICE_STATE_OFF || 
                   toState == DEVICE_STATE_RUNNING);

        default:
            // Invalid from state
            return false;
    }
}

