        ESP_LOGE(TAG, "Failed to open HTTP connection for version check, code=0x%x", last_error);
        return last_error;
    }

    // Check server response status
    auto status_code = http->GetStatusCode();
    if (status_code != 200)
    {
        ESP_LOGE(TAG, "Failed to check version, status code: %d", status_code);
        return status_code;
    }

    // Read response data
    std::string data;
    if (!http->ReadData(&data))
    {
