        return ESP_FAIL;
    }

    // Parse JSON response
    cJSON *root = cJSON_Parse(data.c_str());
    if (root == NULL)
    {
        const char *error_ptr = cJSON_GetErrorPtr();
        if (error_ptr != NULL)
        {
            ESP_LOGE(TAG, "JSON parse error in version check: %s", error_ptr);
        }
        return ESP_FAIL;
    }

    // Extract version and download URL from JSON
    cJSON *version_item = cJSON_GetObjectItem(root, "version");
    cJSON *url_item = cJSON_GetObjectItem(root, "url");

    if (!version_item || !url_item)
    {
        ESP_LOGE(TAG, "Missing version or url in version check response");
        cJSON_Delete(root);
        return ESP_FAIL;
    }

    newVersion = cJSON_GetStringValue(version_item);
    downloadUrl = cJSON_GetStringValue(url_item);

    // Check if new version is available
    if (IsNewVersionAvailable(currentVersion, newVersion))
    {
        ESP_LOGI(TAG, "New version available: %s (current: %s)", newVersion.c_str(), currentVersion.c_str());
        cJSON_Delete(root);
        return ESP_OK;
    }
    else
    {
        ESP_LOGI(TAG, "No new version available (current: %s)", currentVersion.c_str());
        cJSON_Delete(root);
        return ESP_ERR_NOT_FOUND;
    }
}

