// OTA upgrade function signature
bool Ota::Upgrade(const std::string &url, std::function<void(int progress, size_t speed)> callback)
{
    // Initialize variables
    esp_partition_t const *update_partition = nullptr;
    esp_ota_handle_t update_handle = 0;
    std::string image_header;
    bool image_header_checked = false;

    // Get OTA partition
    const esp_partition_t *running = esp_ota_get_running_partition();
    update_partition = esp_ota_get_next_update_partition(running);
    if (update_partition == nullptr) {
        ESP_LOGE(TAG, "Failed to get OTA partition");
        return false;
    }

    // Open HTTP connection
    auto http = SetupHttp();
    if (!http->Open("GET", url)) {
        ESP_LOGE(TAG, "Failed to open HTTP connection");
        return false;
    }

    // Download and write firmware
    uint8_t buffer[1024];
    size_t total_size = 0;
    size_t downloaded = 0;
    size_t speed = 0;
    uint64_t start_time = esp_timer_get_time();

    while (true) {
        int ret = http->Read(buffer, sizeof(buffer));
        if (ret <= 0) break;

        downloaded += ret;
        total_size = http->GetContentLength();

        // Calculate speed
        uint64_t elapsed = esp_timer_get_time() - start_time;
        if (elapsed > 0) {
            speed = (downloaded * 1000000ULL) / elapsed; // bytes/sec
        }

        // Report progress
        if (callback && total_size > 0) {
            int progress = (downloaded * 100) / total_size;
            callback(progress, speed);
        }

        if (!image_header_checked) {
            image_header.append(buffer, ret);
            if (image_header.size() >= sizeof(esp_image_header_t) + sizeof(esp_image_segment_header_t) + sizeof(esp_app_desc_t)) {
                // Verify firmware header
                esp_app_desc_t new_app_info;
                memcpy(&new_app_info, image_header.data() + sizeof(esp_image_header_t) + sizeof(esp_image_segment_header_t), sizeof(esp_app_desc_t));

                auto current_version = esp_app_get_description()->version;
                ESP_LOGI(TAG, "Current version: %s, New version: %s", current_version, new_app_info.version);

                if (esp_ota_begin(update_partition, OTA_WITH_SEQUENTIAL_WRITES, &update_handle)) {
                    esp_ota_abort(update_handle);
                    ESP_LOGE(TAG, "Failed to begin OTA");
                    return false;
                }

                image_header_checked = true;
                std::string().swap(image_header);
            }
        }

        auto err = esp_ota_write(update_handle, buffer, ret);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to write OTA data: %s", esp_err_to_name(err));
            esp_ota_abort(update_handle);
            return false;
        }
    }

    http->Close();

    // Finalize OTA update
    esp_err_t err = esp_ota_end(update_handle);
    if (err != ESP_OK) {
        if (err == ESP_ERR_OTA_VALIDATE_FAILED) {
            ESP_LOGE(TAG, "Image validation failed, image is corrupted");
        } else {
            ESP_LOGE(TAG, "Failed to end OTA: %s", esp_err_to_name(err));
        }
        return false;
    }

    err = esp_ota_set_boot_partition(update_partition);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to set boot partition: %s", esp_err_to_name(err));
        return false;
    }

    ESP_LOGI(TAG, "Firmware upgrade successful");
    return true;
}
```

### Key Implementation Patterns:

1. **OTA Partition Management**:
   - Use `esp_ota_get_next_update_partition()` to find the correct OTA partition
   - Use `esp_ota_begin()`, `esp_ota_write()`, and `esp_ota_end()` for OTA operations

2. **HTTP Download with Progress Reporting**:
