void CustomWakeWord::ParseWakenetModelConfig() {
    const char* config_path = "/sdcard/index.json";
    FILE* file = fopen(config_path, "r");
    if (!file) {
        ESP_LOGE(TAG, "Failed to open config file: %s", config_path);
        return;
    }

    fseek(file, 0, SEEK_END);
    long length = ftell(file);
    fseek(file, 0, SEEK_SET);

    char* buffer = new char[length + 1];
    fread(buffer, 1, length, file);
    buffer[length] = '\0';
    fclose(file);

    cJSON* root = cJSON_Parse(buffer);
    if (!root) {
        ESP_LOGE(TAG, "Failed to parse JSON config");
        delete[] buffer;
        return;
    }

    // Extract language
    cJSON* lang_item = cJSON_GetObjectItem(root, "language");
    if (lang_item && cJSON_IsString(lang_item)) {
        language_ = lang_item->valuestring;
    }

    // Extract duration
    cJSON* duration_item = cJSON_GetObjectItem(root, "duration");
    if (duration_item && cJSON_IsNumber(duration_item)) {
        duration_ = duration_item->valuedouble;
    }

    // Extract threshold
    cJSON* threshold_item = cJSON_GetObjectItem(root, "threshold");
    if (threshold_item && cJSON_IsNumber(threshold_item)) {
        threshold_ = threshold_item->valuedouble;
    }

    // Extract commands
    cJSON* commands_item = cJSON_GetObjectItem(root, "commands");
    if (cJSON_IsArray(commands_item)) {
        int num_commands = cJSON_GetArraySize(commands_item);
        for (int i = 0; i < num_commands; i++) {
            cJSON* cmd_obj = cJSON_GetArrayItem(commands_item, i);
            cJSON* cmd_name = cJSON_GetObjectItem(cmd_obj, "name");
            cJSON* cmd_display = cJSON_GetObjectItem(cmd_obj, "display");
            cJSON* cmd_action = cJSON_GetObjectItem(cmd_obj, "action");

            if (cmd_name && cJSON_IsString(cmd_name) &&
