void InitializeSt7789Display() {
    // Create SPI panel IO handle
    esp_lcd_panel_io_handle_t panel_io = nullptr;
    esp_lcd_panel_io_spi_config_t io_config = {
        .dc_gpio_num = LCD_DC_PIN,
        .cs_gpio_num = LCD_CS_PIN,
        .pclk_hz = LCD_PIXEL_CLOCK_FREQ_HZ,
        .lcd_cmd_bits = 8,
        .lcd_param_bits = 8,
        .spi_mode = 0,
        .trans_queue_depth = 10,
        .on_color_trans_done = nullptr,
        .user_ctx = nullptr,
        .flags = {
            .dc_as_cmd_phase = 1,
            .dc_low_on_data = 0,
            .octal_mode = 0,
        },
    };

    ESP_ERROR_CHECK(esp_lcd_new_panel_io_spi((esp_lcd_spi_bus_handle_t)SPI2_HOST, &io_config, &panel_io));

    // Create ST7789 panel handle
    esp_lcd_panel_handle_t panel_handle = nullptr;
    esp_lcd_panel_dev_config_t panel_config = {
        .reset_gpio_num = LCD_RST_PIN,
        .rgb_endian = LCD_RGB_ENDIAN,
        .bits_per_pixel = 16,
    };

    ESP_ERROR_CHECK(esp_lcd_new_panel_st7789(panel_io, &panel_config, &panel_handle));

    // Initialize display with rotation settings
    esp_lcd_panel_reset(panel_handle);
    esp_lcd_panel_init(panel_handle);
    esp_lcd_panel_invert_color(panel_handle, true); // Enable color inversion
    esp_lcd_panel_swap_xy(panel_handle, true);      // Swap X/Y axes
    esp_lcd_panel_mirror(panel_handle, true, true); // Mirror both axes

    // Create display object
    display_ = new SpiLcdDisplay(
        panel_io, 
        panel_handle, 
        DISPLAY_WIDTH, 
        DISPLAY_HEIGHT, 
        0, 0,  // offset_x, offset_y
        false, false,  // mirror_x, mirror_y
        true   // swap_xy
    );
}
