                                     WifiManager *wifi_manager,
                                     Display *display,
                                     size_t channel) {
    // Initialize audio signal processor for WiFi credential detection
    // Using typical frequencies for audio-based data transmission
    AudioSignalProcessor processor(44100, 1200, 2200, 1200, 1024);

    // Create audio data buffer for receiving WiFi credentials
    // Using default patterns and enabling checksum validation
    AudioDataBuffer buffer(100, kDefaultStartTransmissionPattern, 
                           kDefaultEndTransmissionPattern, true);

    // Get audio input from the specified channel
    AudioInput* audio_input = app->GetAudioInput(channel);

    if (!audio_input) {
        ESP_LOGE("WiFiReceiver", "Failed to get audio input for channel %zu", channel);
        if (display) {
            display->ShowErrorMessage("Audio input error");
        }
        return;
    }

    // Main processing loop
    while (true) {
        // Read audio samples from the input
        std::vector<float> audio_samples = audio_input->ReadSamples();

        if (audio_samples.empty()) {
            // No samples available, continue loop
            continue;
        }

        // Process audio samples using Goertzel algorithm
        std::vector<float> processed_samples = processor.ProcessAudioSamples(audio_samples);

        // Process probability data to extract encoded information
        bool success = buffer.ProcessProbabilityData(processed_samples, 0.5f);

        if (success) {
            // Successfully decoded data
            std::string wifi_credentials = buffer.decoded_text;

            // Validate that we have meaningful credentials
            if (!wifi_credentials.empty()) {
                ESP_LOGI("WiFiReceiver", "Received WiFi credentials: %s", wifi_credentials.c_str());

                // Extract SSID and password (assuming format: "SSID:PASSWORD")
                size_t colon_pos = wifi_credentials.find(':');
                if (colon_pos != std::string::npos) {
                    std::string ssid = wifi_credentials.substr(0, colon_pos);
                    std::string password = wifi_credentials.substr(colon_pos + 1);

