std::vector<uint8_t> ConvertBitsToBytes(const std::vector<uint8_t>& bits) const {
    std::vector<uint8_t> result;
    if (bits.empty()) return result;

    // Process every 8 bits to form a byte
    for (size_t i = 0; i < bits.size(); i += 8) {
        uint8_t byte = 0;
        // Handle cases where less than 8 bits remain
        size_t end = std::min(i + 8, bits.size());
        for (size_t j = i; j < end; ++j) {
            byte |= (bits[j] << (7 - (j - i)));
        }
        result.push_back(byte);
    }
    return result;
}
