std::string GetSystemInfoJson() {
    // Create JSON object
    cJSON* root = cJSON_CreateObject();

    // Get OTA information
    esp_app_desc_t app_desc;
    esp_err_t ret = esp_ota_get_app_description(&app_desc);
    if (ret == ESP_OK) {
        cJSON_AddStringToObject(root, "version", app_desc.version);
        cJSON_AddStringToObject(root, "compile_time", app_desc.compile_time);
        cJSON_AddStringToObject(root, "compile_date", app_desc.compile_date);
    }

    // Get chip information
    esp_chip_info_t chip_info;
    esp_chip_info(&chip_info);
    cJSON_AddNumberToObject(root, "chip_model", chip_info.model);
    cJSON_AddNumberToObject(root, "core_count", chip_info.cores);

    // Get flash size
    size_t flash_size;
    esp_flash_get_size(NULL, &flash_size);
    cJSON_AddNumberToObject(root, "flash_size_bytes", flash_size);

    // Get MAC address
    uint8_t mac[6];
    esp_read_mac(mac, ESP_MAC_WIFI_STA);
    char mac_str[18];
    snprintf(mac_str, sizeof(mac_str), "%02X:%02X:%02X:%02X:%02X:%02X",
             mac[0], mac[1], mac[2], mac[3], mac[4], mac[5]);
    cJSON_AddStringToObject(root, "mac_address", mac_str);

    // Get minimum free heap size
    size_t min_free_heap = esp_get_minimum_free_heap_size();
    cJSON_AddNumberToObject(root, "min_free_heap_bytes", min_free_heap);

    // Get partition table data
    const esp_partition_t* partition = esp_partition_find_first(
        ESP_PARTITION_TYPE_DATA, ESP_PARTITION_SUBTYPE_DATA_NVS, NULL);
    if (partition != NULL) {
        cJSON_AddNumberToObject(root, "nvs_partition_size", partition->size);
        cJSON_AddNumberToObject(root, "nvs_partition_address", partition->address);
    }

    // Convert to string
    char* json_str = cJSON_PrintUnformatted(root);
    std::string result(json_str);

    // Clean up
    cJSON_Delete(root);
    free(json_str);

    return result;
}

