void OnWifiConnectTimeout(void *) {
    ESP_LOGW(TAG, "WiFi connection timeout occurred");

    // Stop the connection timer and clean it up
    if (connect_timer_) {
        esp_timer_stop(connect_timer_);
        esp_timer_delete(connect_timer_);
        connect_timer_ = nullptr;
    }

    // Check if we're already in configuration mode to avoid re-entry
    if (in_config_mode_) {
        ESP_LOGI(TAG, "Already in configuration mode, skipping re-entry");
        return;
    }

    // Stop current WiFi station connection
    WifiManager::GetInstance().StopStation();

    // Set device state to indicate we're entering configuration mode
    Application::GetInstance().SetDeviceState(kDeviceStateWifiConfiguring);

    // Enter configuration mode
    StartWifiConfigMode();

    // Log the transition
    ESP_LOGI(TAG, "Transitioned to WiFi configuration mode due to timeout");
}

