bool SendAudio(std::unique_ptr<AudioStreamPacket> packet) {
    // Check if protocol is still alive
    if (!*alive_) {
        ESP_LOGW(TAG, "Protocol is shutting down");
        return false;
    }

    // Lock the UDP channel for thread-safe access
    std::lock_guard<std::mutex> lock(channel_mutex_);
    if (udp_ == nullptr) {
        ESP_LOGE(TAG, "UDP channel not opened");
        return false;
    }

    // Prepare packet data for sending
    auto packet_data = std::make_unique<std::vector<uint8_t>>();

    // Construct nonce using packet metadata
    uint32_t size_be = htonl(packet->payload.size());
    uint32_t timestamp_be = htonl(packet->timestamp);
    uint32_t sequence_be = htonl(local_sequence_++);

    // Combine with aes_nonce_ to form full nonce
    std::vector<uint8_t> nonce = aes_nonce_;
    nonce.insert(nonce.end(), (uint8_t*)&size_be, (uint8_t*)&size_be + 4);
    nonce.insert(nonce.end(), (uint8_t*)&timestamp_be, (uint8_t*)&timestamp_be + 4);
    nonce.insert(nonce.end(), (uint8_t*)&sequence_be, (uint8_t*)&sequence_be + 4);

    // Initialize AES-CTR context for encryption
    mbedtls_aes_init(&aes_ctx_);
    int ret = mbedtls_aes_setkey_enc(&aes_ctx_, (const unsigned char*)DecodeHexString(key).c_str(), 128);
    if (ret != 0) {
        ESP_LOGE(TAG, "AES key setup failed with code: %d", ret);
        mbedtls_aes_free(&aes_ctx_);
        return false;
    }

    // Encrypt the packet payload
    std::vector<uint8_t> encrypted_payload(packet->payload.size());
    ret = mbedtls_aes_crypt_ctr(&aes_ctx_, 
                               packet->payload.size(),
                               0,
                               nonce.data(),
                               nullptr,  // IV will be updated by ctr mode
                               packet->payload.data(),
                               encrypted_payload.data());

    mbedtls_aes_free(&aes_ctx_);

    if (ret != 0) {
        ESP_LOGE(TAG, "Encryption failed with code: %d", ret);
        return false;
    }

    // Assemble final packet with header and encrypted payload
    // Add packet header (size, timestamp, sequence number)
    packet_data->reserve(sizeof(uint32_t) * 3 + encrypted_payload.size());

    // Add size field
    packet_data->insert(packet_data->end(), (uint8_t*)&size_be, (uint8_t*)&size_be + 4);

    // Add timestamp field
    packet_data->insert(packet_data->end(), (uint8_t*)&timestamp_be, (uint8_t*)&timestamp_be + 4);

    // Add sequence number field
    packet_data->insert(packet_data->end(), (uint8_t*)&sequence_be, (uint8_t*)&sequence_be + 4);

    // Add encrypted payload
    packet_data->insert(packet_data->end(), encrypted_payload.begin(), encrypted_payload.end());

    // Send the packet over UDP
    if (!udp_->Send(packet_data->data(), packet_data->size())) {
        ESP_LOGE(TAG, "Failed to send audio packet");
        return false;
    }

