// Example of decoding a hex string into binary data
std::string MqttProtocol::DecodeHexString(const std::string& hex_string) {
    std::string result;
    result.reserve(hex_string.length() / 2);  // Pre-allocate space for efficiency

    for (size_t i = 0; i < hex_string.length(); i += 2) {
        // Ensure we have at least two characters left
        if (i + 1 >= hex_string.length()) {
            // Handle odd-length input - could either ignore or throw an error
            break;
        }

        char high = hex_string[i];
        char low = hex_string[i + 1];

        uint8_t byte = (CharToHex(high) << 4) | CharToHex(low);
        result.push_back(static_cast<char>(byte));
    }

    return result;
}
```

